752	function buildBreakdown(r,sf){
753	  const Fs=[r.Fbrk,r.Fstr,r.FbA,r.FbB],descs=[`Su ${r.gr.Su}×As ${r.b.As}`,`τ ${r.nut.tau} MPa`,`面圧 ${r.bA} MPa`,`面圧 ${r.bB} MPa`];
754	  ['bd0','bd1','bd2','bd3'].forEach((id,i)=>{const isL=Math.abs(Fs[i]-r.Flim)<0.01;ge(id+'v').innerHTML=(Fs[i]/1000).toFixed(2)+'<span class="mc-u">kN</span>';ge(id+'s').textContent=descs[i];ge(id).className='mc '+(isL?'danger':'');});
755	  ge('bd4v').textContent=r.failMode;ge('bd4').className='mc '+(r.failMode==='ボルト破断'?'ok':'danger');
756	  const bkL=['ボルト破断','山飛び','座面A','座面B'],lims=Fs.map(f=>f/1000),reqs=lims.map(v=>Math.min(v,r.Flim/1000)/sf);
757	  mkC('cMG',{type:'bar',data:{labels:bkL,datasets:[{label:'限界軸力',data:lims,backgroundColor:lims.map(v=>Math.abs(v-r.Flim/1000)<0.01?'#E24B4A':'#85B7EB'),borderWidth:0},{label:'要求(/S)',data:reqs,backgroundColor:'#C0DD97',borderWidth:0}]},options:{responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10}},plugins:{legend:{display:false}},scales:{x:{ticks:{font:{size:9}}},y:{title:{display:true,text:'軸力 (kN)',font:{size:9}},ticks:{font:{size:9}},grace:'5%'}}}});
758	  const bkLL=['ボルト破断','山飛び（めねじ）','座面陥没 A面','座面陥没 B面'];
759	  ge('bd-tbl').innerHTML=bkLL.map((l,i)=>{const isL=Math.abs(Fs[i]-r.Flim)<0.01,mg=(Fs[i]/1000)/(r.Flim/1000/sf),tl=r.rows.find(row=>row.F>=(Fs[i]/1000)*0.998)?.T;return `<tr><td>${l}</td><td>${(Fs[i]/1000).toFixed(2)}</td><td>${tl?tl.toFixed(1):'—'}</td><td style="${mg<1.2?'color:#A32D2D':mg<1.5?'color:#854F0B':'color:#3B6D11'}">${mg.toFixed(2)}x</td><td>${isL?'<span class="sb2 s-l">支配的</span>':'—'}</td></tr>`;}).join('');
