const bkLL=['ボルト破断','山飛び（めねじ）','座面陥没 A面','座面陥没 B面'];
const recTorque=r.T_lim?r.T_lim/sf:null;
ge('bd-tbl').innerHTML=bkLL.map((l,i)=>{
  const isL=Math.abs(Fs[i]-r.Flim)<0.01;
  const mg=(Fs[i]/1000)/(r.Flim/1000/sf);
  const limitTorque=(Fs[i]/1000)*r.denom;
  const isDanger=recTorque&&limitTorque<recTorque;
  const torqueStyle=isDanger?'color:#E24B4A;font-weight:bold':isL?'color:#E24B4A;font-weight:bold':'';
  const rowStyle=isL?'background:#FFF5F5':'';
  return `<tr style="${rowStyle}"><td style="${isL?'font-weight:bold':''}"><span style="margin-right:4px">${isL?'⚠':''}</span>${l}</td><td>${(Fs[i]/1000).toFixed(2)}</td><td style="${torqueStyle}">${limitTorque.toFixed(1)}${isDanger?' ⚠':''}</td><td style="${mg<1.2?'color:#A32D2D':mg<1.5?'color:#854F0B':'color:#3B6D11'}">${mg.toFixed(2)}x</td><td>${isL?'<span class="sb2 s-l">支配的</span>':'—'}</td></tr>`;
}).join('');

